#!/usr/bin/env python# run_dashboard.py — Univers par défaut : NIKKEI 225 complet## Usage :#   python run_dashboard.py                    # 185 tickers Nikkei 225 (~3-5 min chargement)#   python run_dashboard.py --universe liquid40 # 40 tickers (démarrage rapide)#   python run_dashboard.py --universe default  # 10 tickers (dev)#   python run_dashboard.py --universe custom --tickers 7203.T,6758.T#   python run_dashboard.py --mode live         # IBKR liveimport argparseimport loggingimport syslogging.basicConfig(    level=logging.INFO,    format="%(asctime)s | %(levelname)-8s | %(name)s | %(message)s",    handlers=[        logging.StreamHandler(sys.stdout),        logging.FileHandler("logs/dashboard.log", mode="a"),    ],)logger = logging.getLogger("run_dashboard")def parse_args():    p = argparse.ArgumentParser(description="NK225 Equity Research Platform")    p.add_argument("--mode",         default="backtest", choices=["backtest","live"])    p.add_argument("--universe",     default="full",     # ← NIKKEI 225 par défaut                   choices=["full","liquid40","default","custom"])    p.add_argument("--tickers",      default="",                   help="Tickers séparés par virgule (mode custom)")    p.add_argument("--start",        default="2022-01-01")    p.add_argument("--end",          default="2026-01-01")    p.add_argument("--host",         default="127.0.0.1")    p.add_argument("--port",         default=8050, type=int)    p.add_argument("--debug",        action="store_true")    p.add_argument("--run-backtest", action="store_true")    p.add_argument("--train-months", type=int, default=12)    p.add_argument("--test-months",  type=int, default=3)    return p.parse_args()def _startup_backtest(ds, tickers, args):    from backtesting.backtest_engine import BacktestEngine, momentum_pipeline    logger.info("▶ Walk-forward de démarrage...")    try:        returns = ds.get_returns(tickers, args.start, args.end)        engine  = BacktestEngine(train_months=args.train_months,                                  test_months=args.test_months)        top_n   = max(5, len(tickers) // 10)        result  = engine.run(returns, lambda r: momentum_pipeline(r, top_n=top_n))        logger.info(f"  Backtest OK — Sharpe {result.metrics['sharpe']:.2f} "                    f"| MaxDD {result.metrics['max_drawdown']:.2%}")        return result    except Exception as e:        logger.warning(f"  Backtest échoué (non bloquant) : {e}")        return Nonedef main():    args = parse_args()    from config.universe import get_universe, NIKKEI_225    if args.universe == "custom" and args.tickers:        tickers = [t.strip() for t in args.tickers.split(",") if t.strip()]    else:        tickers = get_universe(args.universe)    logger.info(f"Mode     : {args.mode}")    logger.info(f"Univers  : {args.universe} → {len(tickers)} tickers")    logger.info(f"Période  : {args.start} → {args.end}")    if args.universe == "full":        logger.info(f"  ⚠ Nikkei 225 complet — premier chargement Yahoo Finance ~3-5 min")        logger.info(f"     Cache activé : les relances suivantes seront instantanées")    from data.data_service import DataService    ds = DataService(mode=args.mode)    backtest_result = None    if args.run_backtest:        backtest_result = _startup_backtest(ds, tickers, args)    from dashboard.data_provider import DashboardDataProvider    dp = DashboardDataProvider(        data_service    = ds,        tickers         = tickers,        start           = args.start,        end             = args.end,        backtest_result = backtest_result,    )    from dashboard.app import build_dashboard    app = build_dashboard(data_provider=dp)    from config.settings import DASH_HOST, DASH_PORT, DASH_DEBUG    host  = args.host  or DASH_HOST    port  = args.port  or DASH_PORT    debug = args.debug or DASH_DEBUG    logger.info(f"Dashboard → http://{host}:{port}")    app.run(host=host, port=port, debug=debug)if __name__ == "__main__":    main()